interface Product {
  id: number;
  name: string;
  price: number;
  description?: string;
  discount?: number;
  tags?: string[];
}

function displayProduct(p: Product): string {
  const desc    = p.description ?? "No description";
  const savings = p.discount ? ` (-${(p.discount*100).toFixed(0)}%)` : "";
  const tagStr  = p.tags?.join(", ") ?? "untagged";
  return `${p.name}$${p.price.toFixed(2)}${savings} | ${desc} | ${tagStr}`;
}

const full: Product = { id: 1, name: "Pro Plan ", price: 49, description: "Full access", discount: 0.2, tags: ["popular", "value"] };
const bare: Product = { id: 2, name: "Starter ",  price: 19 };

console.log(displayProduct(full));
console.log(displayProduct(bare));

