interface Serializable {
  toJSON(): string;
  toString(): string;
}

interface Comparable<T> {
  compareTo(other: T): number;
  equals(other: T): boolean;
}

interface Money extends Serializable, Comparable<Money> {
  amount: number;
  currency: string;
}

class USD implements Money {
  constructor(public amount: number, public currency = "USD") {}
  toJSON()  { return JSON.stringify({ amount: this.amount, currency: this.currency }); }
  toString(){ return `${this.currency} ${this.amount.toFixed(2)}`; }
  compareTo(other: Money): number { return this.amount - other.amount; }
  equals(other: Money): boolean { return this.amount === other.amount && this.currency === other.currency; }
}

const price = new USD(49.99);
const discount = new USD(39.99);

console.log(price.toString());
console.log(price.toJSON());
console.log(`price > discount: ${price.compareTo(discount) > 0}`);
console.log(`equal: ${price.equals(discount)}`);

// Interface: good for object shapes, supports merging
interface Config {
  host: string;
  port: number;
}

// Declaration merging — two declarations merge into one
interface Config {
  debug: boolean;
}

// type: good for unions, intersections, primitives
