  host: "localhost", port: 3000,
  debug: true, timeout: 5000,
};

const id1: Id = 42;
const id2: Id = "user-123";

console.log(`${cfg.host}:${cfg.port} (debug=${cfg.debug}, timeout=${cfg.timeout}ms)`);
