interface EventHandler {
  (event: string, payload: unknown): void;
}

interface Validator<T> {
  (value: T): { valid: boolean; message?: string };
}

interface Transformer<T, U> {
  (input: T): U;
}

const logger: EventHandler = (event, payload) => {
  console.log(`Event: ${event} | ${JSON.stringify(payload)}`);
};

const validateAge: Validator<number> = (age) => {
  if (age < 0 || age > 150) return { valid: false, message: `Invalid age: ${age}` };
  return { valid: true };
};

const numToStr: Transformer<number, string> = (n) => `$${n.toFixed(2)}`;

logger("user.login", { userId: 42 });
console.log(validateAge(25));
console.log(validateAge(-5));
console.log(numToStr(49.99));

