interface KVStore {
  get(key: string): string | null;
  set(key: string, value: string): void;
  delete(key: string): boolean;
  keys(): string[];
}

class MemoryStore implements KVStore {
  private data = new Map<string, string>();
  get(k: string): string | null      { return this.data.get(k) ?? null; }
  set(k: string, v: string): void    { this.data.set(k, v); }
  delete(k: string): boolean         { return this.data.delete(k); }
  keys(): string[]                   { return [...this.data.keys()]; }
}

function useStore(store: KVStore): void {
  store.set("lang", "typescript");
  store.set("version", "5.3");
  store.set("debug", "false");
  console.log(`Keys: ${store.keys().join(", ")}`);
  console.log(`lang: ${store.get("lang")}`);
  store.delete("debug");
  console.log(`After delete: ${store.keys().join(", ")}`);
}

useStore(new MemoryStore());

interface EmailNotification {
  type: "email";
  to: string;
  subject: string;
  body: string;
}

interface PushNotification {
  type: "push";
  deviceToken: string;
  title: string;
  message: string;
  badge?: number;
}

interface SMSNotification {
  type: "sms";
  phoneNumber: string;
  message: string;
}

type Notification = EmailNotification | PushNotification | SMSNotification;

function sendNotification(n: Notification): string {
  switch (n.type) {
    case "email": return `Email to ${n.to}: ${n.subject}`;
    case "push":  return `Push to device: ${n.title}`;
    case "sms":   return `SMS to ${n.phoneNumber}`;
  }
}

const notifications: Notification[] = [
  { type: "email", to: "alice@co.com", subject: "Welcome!", body: "..." },
  { type: "push",  deviceToken: "tok_xyz", title: "New message", message: "You have a message" },
  { type: "sms",   phoneNumber: "+1234567890", message: "Your code: 123456" },
];

for (const n of notifications) console.log(sendNotification(n));

