interface Repository<T, TId> {
  findById(id: TId): T | undefined;
  findAll(): T[];
  save(item: T): T;
  delete(id: TId): boolean;
  count(): number;
}

interface User { id: number; name: string; email: string }

class InMemoryUserRepo implements Repository<User, number> {
  private users: User[] = [];

  findById(id: number): User | undefined { return this.users.find(u => u.id === id); }
  findAll(): User[]                      { return [...this.users]; }
  save(user: User): User                 { this.users.push(user); return user; }
  delete(id: number): boolean            { const i = this.users.findIndex(u => u.id === id); if (i < 0) return false; this.users.splice(i, 1); return true; }
  count(): number                        { return this.users.length; }
}

const repo = new InMemoryUserRepo();
repo.save({ id: 1, name: "Alice", email: "alice@co.com" });
repo.save({ id: 2, name: "Bob",   email: "bob@co.com" });
repo.save({ id: 3, name: "Carol", email: "carol@co.com" });

console.log(`Count: ${repo.count()}`);
console.log(`Find 2: ${repo.findById(2)?.name}`);
repo.delete(2);
console.log(`After delete: ${repo.count()}`);
console.log(`Users: ${repo.findAll().map(u => u.name).join(", ")}`);

